import * as Camera from 'expo-camera';
import { Alert, Linking } from 'react-native';

async function ensureCameraPermission(): Promise<boolean> {
  // Step 1: read current state without triggering a dialog
  const { status, canAskAgain } = await Camera.getCameraPermissionsAsync();

  if (status === 'granted') {
    return true;
  }

  // Step 2: iOS 'denied' is permanent; Android checks canAskAgain
  if (status === 'denied' && !canAskAgain) {
    Alert.alert(
      'Camera Access Required',
      'Please enable camera access in Settings to scan documents.',
      [
        { text: 'Cancel', style: 'cancel' },
        { text: 'Open Settings', onPress: () => Linking.openSettings() },
      ]
    );
    return false;
  }

  // Step 3: show rationale BEFORE the system dialog (iOS best practice)
  await new Promise<void>(resolve =>
    Alert.alert(
      'Camera Access',
      'The camera is needed to capture and analyze document images with Claude.',
      [{ text: 'Continue', onPress: resolve }]
    )
  );

  // Step 4: request
  const { status: newStatus } = await Camera.requestCameraPermissionsAsync();
  return newStatus === 'granted';
}

