import * as Location from 'expo-location';

async function getLocationForClaude(): Promise<string | null> {
  const { status } = await Location.requestForegroundPermissionsAsync();
  if (status !== 'granted') return null;

  // Accuracy.Lowest uses cell/wifi — fast and battery-friendly
  const loc = await Location.getCurrentPositionAsync({
    accuracy: Location.Accuracy.Lowest,
  });

  // Convert to city name via reverse geocoding
  const [place] = await Location.reverseGeocodeAsync(loc.coords);
  return `${place.city}, ${place.region}`;
}

import { useState, useCallback } from 'react';
import { Alert, Linking } from 'react-native';

type PermissionStatus = 'granted' | 'denied' | 'undetermined' | 'blocked';

interface PermissionHook {
  status: PermissionStatus;
  request: () => Promise<boolean>;
  openSettings: () => void;
}

type PermissionGetter = () => Promise<{ status: PermissionStatus; canAskAgain: boolean }>;
type PermissionRequester = () => Promise<{ status: PermissionStatus }>;

export function usePermission(
  getter: PermissionGetter,
  requester: PermissionRequester,
  rationaleTitle: string,
  rationaleMessage: string
): PermissionHook {
  const [status, setStatus] = useState<PermissionStatus>('undetermined');

  const openSettings = useCallback(() => Linking.openSettings(), []);

  const request = useCallback(async (): Promise<boolean> => {
    const { status: current, canAskAgain } = await getter();

    if (current === 'granted') {
      setStatus('granted');
      return true;
    }

    if (current === 'denied' && !canAskAgain) {
      setStatus('blocked');
      return false;
    }

    // Show rationale before the OS dialog
    await new Promise<void>(resolve =>
      Alert.alert(rationaleTitle, rationaleMessage, [
        { text: 'Continue', onPress: resolve },
      ])
    );

    const { status: next } = await requester();
    const granted = next === 'granted';
    setStatus(granted ? 'granted' : (canAskAgain ? 'denied' : 'blocked'));
    return granted;
  }, [getter, requester, rationaleTitle, rationaleMessage]);

  return { status, request, openSettings };
}

